// generate-icon.js - Auto-generates icon.ico from embedded base64 PNG
const fs = require('fs');
const path = require('path');

// Base64 encoded PNG icon
const base64png = '';

// Write PNG file
const pngBuffer = Buffer.from(base64png, 'base64');
fs.writeFileSync(path.join(__dirname, 'icon.png'), pngBuffer);
console.log('icon.png written successfully');

// Create a minimal valid ICO file from the PNG
// ICO header + PNG data
const iconHeader = Buffer.alloc(6);
iconHeader.writeUInt16LE(0, 0);  // Reserved
iconHeader.writeUInt16LE(1, 2);  // Type: ICO
iconHeader.writeUInt16LE(1, 4);  // Number of images

const iconDir = Buffer.alloc(16);
iconDir.writeUInt8(0, 0);   // Width (0 = 256)
iconDir.writeUInt8(0, 1);   // Height (0 = 256)
iconDir.writeUInt8(0, 2);   // Color count
iconDir.writeUInt8(0, 3);   // Reserved
iconDir.writeUInt16LE(1, 4); // Planes
iconDir.writeUInt16LE(32, 6); // Bit count
iconDir.writeUInt32LE(pngBuffer.length, 8); // Size of PNG data
iconDir.writeUInt32LE(22, 12); // Offset of PNG data (6 header + 16 dir)

const icoBuffer = Buffer.concat([iconHeader, iconDir, pngBuffer]);
fs.writeFileSync(path.join(__dirname, 'icon.ico'), icoBuffer);
console.log('icon.ico written successfully (' + icoBuffer.length + ' bytes)');
